INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('3dafb905-9745-5efc-a34a-887ff8a71971', '0f100836-fb26-4616-b6e9-20800e0d6a23', 'You should see ___ Smith if you feel sick.', '如果你感到不舒服，你應該去看史密斯醫生。', 'Dr.', 'Mr.', 'Ms.', 'Mrs.', 'Dr. 為 Doctor 的縮寫，意為醫生。', '看到 Dr. 就要聯想到 Doctor (醫生)。', '2026-07-07 05:34:42', '2026-07-07 05:34:42'),
('b9f1f965-b340-57b9-b289-b2705d865f39', '91f36ad7-0c00-4b74-a5a0-dad4242a9177', 'The brave ___ underwent years of intense training before embarking on the mission to the International Space Station.', '這位勇敢的太空人在執行前往國際太空站的任務之前，接受了多年的高強度訓練。', 'astronaut', 'pilot', 'scientist', 'soldier', 'astro- (星星) + naut (航海者) → 航行於星際的人。', 'astro (星星) + naut (水手/航海者) → 在星星之間航行的人 → 太空人。', '2026-07-07 01:40:11', '2026-07-07 01:40:11'),
('5b3b6833-e0ad-59ac-83c1-73ad519a1829', '06015372-66ed-4e4e-894f-ade889deb2af', 'My father is very ___ with his new job.', '我父親因為他的新工作非常忙碌。', 'busy', 'happy', 'tired', 'angry', 'adj. 忙碌的', '想像一隻忙碌的小蜜蜂 → busy bee。', '2026-07-07 09:03:39', '2026-07-07 09:03:39'),
('372ff770-3425-57c5-8578-cbc5b1376339', '1eef27e2-eb0c-4351-b371-b5cbe5b64c19', 'I like to eat ___ for dessert.', '我喜歡吃巧克力當甜點。', 'chocolate', 'bread', 'rice', 'meat', '源自於古代語言，指一種甜食。', '巧克力 (chocolate) 是甜甜的，吃起來心情會很好。', '2026-07-07 03:50:01', '2026-07-07 03:50:01'),
('0ab75f86-2a8c-596c-b8cc-bf6823aae039', 'd79d6566-746f-41ab-a5c1-cc307656b585', 'The teacher asked me to ___ the beautiful sunset.', '老師要求我描述那場美麗的日落。', 'describe', 'imagine', 'watch', 'forget', 'de (強調) + scribe (寫) → 描述', 'de (向下) + scribe (寫) → 把細節寫下來 → 描述', '2026-07-07 03:29:05', '2026-07-07 03:29:05'),
('41400c2b-dce6-5f6e-9270-b0d00df867b9', 'ae7296b4-233c-40c7-89e1-604285cd516b', 'Everyone in my class likes music ___ Tom.', '我們班的所有人都喜歡音樂，除了 Tom 之外。', 'except', 'including', 'during', 'beside', 'ex- (向外) + cept (拿) → 把...拿出去 → 除了...之外', '想像把某人從群體中「拿出去」(take out)，就是「除了」的意思', '2026-07-07 05:04:46', '2026-07-07 05:04:46'),
('69ffa608-df80-5a07-9055-e05ff923193d', '0b994cbb-35f3-4ef0-a95a-70ecd51e8a90', 'He is ___ a teacher; he is a student.', '他不是一名老師；他是一名學生。', 'not', 'always', 'still', 'really', '表示「不」的否定副詞。', '看到 not 就想到 no，代表「不」的意思。', '2026-07-05 13:11:57', '2026-07-05 13:11:57'),
('e82fc05e-a981-56a9-8600-3b0b62d8709d', '05737cfc-81a1-42b1-9d5d-0c18e7a4370a', 'Despite the heavy rain, the protesters decided to carry ___ with their march.', '儘管大雨滂沱，示威者仍決定繼續他們的遊行。', 'on', 'out', 'away', 'back', '副詞，與 carry 連用表示「繼續」。', 'carry (攜帶) + on (繼續) → 繼續做某事。', '2026-07-05 12:20:47', '2026-07-05 12:20:47'),
('91048a11-3bd4-5875-bca1-7100c570b4a9', '20d6333f-d9da-4330-b0cf-8ed640c01ec4', 'He wrote a letter ___ his friend.', '他給他的朋友寫了一封信。', 'to', 'from', 'with', 'for', '表示動作的「對象」。', 'write to → 寫給某人', '2026-07-05 09:19:21', '2026-07-05 09:19:21'),
('16a82348-367a-5aeb-bc83-a81470539759', '3b6d71bc-c21a-4e22-b65f-737a9076bf81', 'Do you know ___ the class ends?', '你知道課程什麼時候結束嗎？', 'when', 'where', 'why', 'how', '此字為疑問副詞或代名詞，用來詢問時間。', 'W-H 系列疑問詞，問時間用 when。', '2026-07-06 10:47:32', '2026-07-06 10:47:32'),
('c7db5e62-fe55-5dd3-bf7c-2f3533e2fcfd', '3587d666-9fcf-40fb-a1a0-9a7c8bcc4474', 'The photographer adjusted the lens to ___ in on the subject, making the distant bird appear much larger in the frame.', '攝影師調整了鏡頭以將畫面推近主體，使畫面中那隻遠處的鳥看起來大得多。', 'zoom', 'move', 'lean', 'turn', 'zoom 為擬聲詞，模擬快速移動或發出嗡嗡聲的聲音 → 意即變焦或快速移動。', '想像賽車『咻』的一聲快速 zoom 過去，或相機鏡頭變焦的動作。', '2026-07-06 09:46:38', '2026-07-06 09:46:38');
